import{fromUserExtent,fromUserResolution,toUserExtent}from"./proj.js";function all(t,e){return[[-1/0,-1/0,1/0,1/0]]}function bbox(t,e){return[t]}function tile(u){return function(t,e,o){var e=u.getZForResolution(fromUserResolution(e,o)),r=u.getTileRangeForExtentAndZ(fromUserExtent(t,o),e),n=[],i=[e,0,0];for(i[1]=r.minX;i[1]<=r.maxX;++i[1])for(i[2]=r.minY;i[2]<=r.maxY;++i[2])n.push(toUserExtent(u.getTileCoordExtent(i),o));return n}}export{all,bbox,tile};